	@Override
	public String instrucciones_reinstalar_forge() {
		return "<html><body style='width: 500px;'>" + "<h3 style='color:#" + config.obtenerColorTitulo()
				+ "'>бһҖбһ¶бһҡбһҺбҹӮбһ“бһ¶бҹҶбһҹбһҳбҹ’бһҡбһ¶бһ”бҹӢбһҠбҹҶбһЎбһҫбһ„ Forge бһЎбһҫбһ„бһңбһ·бһүбҹ–</h3>" + "<ol>"
				+ "<li>бһ‘бһ¶бһүбһҷбһҖбһҖбһҳбҹ’бһҳбһңбһ·бһ’бһёбһҠбҹҶбһЎбһҫбһ„ Forge бһҸбҹ’бһҡбһ№бһҳбһҸбҹ’бһҡбһјбһңбһ–бһёбһӮбҹҒбһ бһ‘бҹҶбһ–бҹҗбһҡбһ•бҹ’бһӣбһјбһңбһҖбһ¶бһҡ (бһҖбҹҶбһҺбҹӮбһҠбҹӮбһӣбһҺбҹӮбһ“бһ¶бҹҶбһҹбһҳбҹ’бһҡбһ¶бһ”бҹӢбһҖбҹҶбһҺбҹӮ Minecraft бһҡбһ”бһҹбҹӢбһўбҹ’бһ“бһҖ)</li>"
				+ "<li>бһ”бһ·бһ‘ launcher Minecraft бһҡбһ”бһҹбҹӢбһўбҹ’бһ“бһҖбһұбҹ’бһҷбһўбһҹбҹӢбһ‘бһ¶бҹҶбһ„бһҹбҹ’бһҡбһ»бһ„</li>"
				+ "<li>бһҠбҹҶбһҺбһҫбһҡбһҖбһ¶бһҡбһҖбһҳбҹ’бһҳбһңбһ·бһ’бһёбһҠбҹҶбһЎбһҫбһ„ Forge бһҮбһ¶ administrator</li>"
				+ "<li>бһҮбҹ’бһҡбһҫбһҹбһҮбһҳбҹ’бһҡбһҫбһҹ 'Installer' (бһҳбһ·бһ“бһҳбҹӮбһ“ 'Installer (run client)')</li>"
				+ "<li>бһҮбҹ’бһҡбһҫбһҹбһҗбһҸ profile Minecraft бһҡбһ”бһҹбҹӢбһўбҹ’бһ“бһҖбһ“бҹ…бһҖбҹ’бһ“бһ»бһ„ launcher</li>"
				+ "<li>бһ…бһ»бһ… 'OK' бһ бһҫбһҷбһҡбһ„бҹӢбһ…бһ¶бҹҶбһҡбһ бһјбһҸбһҠбһӣбҹӢбһҖбһ¶бһҡбһҠбҹҶбһЎбһҫбһ„бһ…бһ”бҹӢ</li>"
				+ "<li>бһ…бһ¶бһ”бҹӢбһ•бҹ’бһҸбһҫбһҳ launcher бһЎбһҫбһ„бһңбһ·бһү бһ бһҫбһҷбһ–бһ·бһ“бһ·бһҸбҹ’бһҷбһҗбһ¶ Forge бһ”бһ„бҹ’бһ бһ¶бһүбһ“бҹ…бһҖбҹ’бһ“бһ»бһ„бһ”бһүбҹ’бһҮбһё profiles</li>" + "</ol>"
				+ "<p><b>бһ…бҹҶбһҺбһ¶бҹҶбһҹбҹҶбһҒбһ¶бһ“бҹӢбҹ–</b> бһ”бҹ’бһҡбһҹбһ·бһ“бһ”бһҫбһўбҹ’бһ“бһҖбһ”бҹ’бһҡбһҫ launcher бһ•бҹ’бһ‘бһ¶бһӣбҹӢбһҒбҹ’бһӣбһҪбһ“ бһҹбһјбһҳбһ”бҹ’бһҡбһ¶бһҖбһҠбһҗбһ¶бһўбҹ’бһ“бһҖбһ”бһ¶бһ“бһҮбҹ’бһҡбһҫбһҹбһҗбһҸ profile бһҸбҹ’бһҡбһ№бһҳбһҸбҹ’бһҡбһјбһңбҹ”</p>"
				+ "</body></html>";
	}

