	@Override
	public String errorMetadataModsTomlFaltante(String modIdFaltante, List<String> modsPotenciales) {
		StringBuilder mensaje = new StringBuilder("<b style='color:#" + config.obtenerColorError() + "'>");
		mensaje.append("бһҖбҹҶбһ бһ»бһҹбһ’бҹ’бһ„бһ“бҹӢбһ’бҹ’бһ„бһҡбҹ– бһҒбҹ’бһңбҹҮ metadata бһҹбһҳбҹ’бһҡбһ¶бһ”бҹӢ modid '").append(modIdFaltante).append("'бҹ” ");

		if (modsPotenciales != null && !modsPotenciales.isEmpty()) {
			mensaje.append("бһҳбҹүбһјбһҠбһҒбһ¶бһ„бһҖбҹ’бһҡбҹ„бһҳбһўбһ¶бһ…бһҮбһ¶бһҳбһјбһӣбһ бҹҒбһҸбһ»бһ“бҹғбһ”бһүбҹ’бһ бһ¶бҹ– <b>");
			for (int i = 0; i < Math.min(modsPotenciales.size(), 3); i++) {
				mensaje.append(modsPotenciales.get(i));
				if (i < modsPotenciales.size() - 1 && i < 2)
					mensaje.append(", ");
			}
			if (modsPotenciales.size() > 3)
				mensaje.append(", бһ“бһ·бһ„бһ•бҹ’бһҹбҹҒбһ„бһ‘бҹҖбһҸ...");
			mensaje.append("</b>бҹ” ");
		}

		mensaje.append("бһңбһ¶бһҖбһҫбһҸбһЎбһҫбһ„бһ“бҹ…бһ–бҹҒбһӣ mod бһҳбһҪбһҷбһ–бһ№бһ„бһ•бҹ’бһўбҹӮбһҖбһӣбһҫ mod бһ•бҹ’бһҹбҹҒбһ„бһ‘бҹҖбһҸбһҠбҹӮбһӣбһҳбһ·бһ“бһ”бһ¶бһ“бһҠбҹҶбһЎбһҫбһ„ бһ¬бһҳбһ¶бһ“бһҜбһҖбһҹбһ¶бһҡ mods.toml бһҳбһ·бһ“бһҸбҹ’бһҡбһ№бһҳбһҸбҹ’бһҡбһјбһңбҹ”");
		mensaje.append("</b>");

		return mensaje.toString();
	}

