	@Override
	public String paso1_metadata_mods_toml_faltante(String modIdFaltante, List<String> modsPotenciales) {
		if (modsPotenciales != null && !modsPotenciales.isEmpty()) {
			StringBuilder paso = new StringBuilder("бһҳбҹүбһјбһҠбһҒбһ¶бһ„бһҖбҹ’бһҡбҹ„бһҳбһ–бһ№бһ„бһ•бҹ’бһўбҹӮбһҖбһӣбһҫ '").append(modIdFaltante).append("': <b>");
			for (int i = 0; i < Math.min(modsPotenciales.size(), 3); i++) {
				paso.append(modsPotenciales.get(i));
				if (i < modsPotenciales.size() - 1 && i < 2)
					paso.append(", ");
			}
			if (modsPotenciales.size() > 3)
				paso.append(", бһ“бһ·бһ„бһ•бҹ’бһҹбҹҒбһ„бһ‘бҹҖбһҸ...");
			paso.append("</b>бҹ” бһ”бҹ’бһҡбһҫбһҳбһ»бһҒбһ„бһ¶бһҡ <b>Arbol de Mods</b> бһҠбһҫбһҳбҹ’бһ”бһёбһ”бһүбҹ’бһҮбһ¶бһҖбҹӢбһҗбһ¶ mod бһҳбһҪбһҷбһҺбһ¶бһҖбҹҶбһ–бһ»бһ„бһ”бһ„бҹ’бһҖбһ”бһүбҹ’бһ бһ¶");
			return paso.toString();
		}
		return "бһҳбһ¶бһ“ mod бһҳбһҪбһҷбһҖбҹҶбһ–бһ»бһ„бһ–бһ№бһ„бһ•бҹ’бһўбҹӮбһҖбһӣбһҫ '" + modIdFaltante
				+ "' бһ”бҹүбһ»бһ“бҹ’бһҸбҹӮ mod бһ“бҹҒбҹҮбһҳбһ·бһ“бһ”бһ¶бһ“бһҠбҹҶбһЎбһҫбһ„бҹ” бһ”бҹ’бһҡбһҫбһҳбһ»бһҒбһ„бһ¶бһҡ <b>Arbol de Mods</b> бһҠбһҫбһҳбҹ’бһ”бһёбһҡбһҖбһғбһҫбһү mod бһҠбҹӮбһӣбһ”бһ„бҹ’бһҖбһ”бһүбҹ’бһ бһ¶";
	}

