	@Override
	public String errorAzureGeckoLibInicializoPronto(boolean azureLibError, boolean geckoLibError,
			boolean connectorPresente) {
		StringBuilder mensaje = new StringBuilder("<b style='color:#" + config.obtenerColorError() + "'>");

		if (azureLibError && geckoLibError) {
			mensaje.append("бһҖбҹҶбһ бһ»бһҹбһ’бҹ’бһ„бһ“бҹӢбһ’бҹ’бһ„бһҡбҹ– AzureLib бһ“бһ·бһ„ GeckoLib бһҸбҹ’бһҡбһјбһңбһ”бһ¶бһ“бһ…бһ¶бһ”бҹӢбһ•бҹ’бһҸбһҫбһҳбһӣбһҝбһ“бһ–бҹҒбһҖ! ");
		} else if (azureLibError) {
			mensaje.append("бһҖбҹҶбһ бһ»бһҹбһ’бҹ’бһ„бһ“бҹӢбһ’бҹ’бһ„бһҡбҹ– AzureLib бһҸбҹ’бһҡбһјбһңбһ”бһ¶бһ“бһ…бһ¶бһ”бҹӢбһ•бҹ’бһҸбһҫбһҳбһӣбһҝбһ“бһ–бҹҒбһҖ! ");
		} else if (geckoLibError) {
			mensaje.append("бһҖбҹҶбһ бһ»бһҹбһ’бҹ’бһ„бһ“бҹӢбһ’бҹ’бһ„бһҡбҹ– GeckoLib бһҸбҹ’бһҡбһјбһңбһ”бһ¶бһ“бһ…бһ¶бһ”бҹӢбһ•бҹ’бһҸбһҫбһҳбһӣбһҝбһ“бһ–бҹҒбһҖ! ");
		}

		mensaje.append("бһңбһ¶бһҖбһҫбһҸбһЎбһҫбһ„бһ“бҹ…бһ–бҹҒбһӣбһ”бҹ’бһҡбһҫ mods Fabric бһҮбһ¶бһҳбһҪбһҷ library бһҠбҹӮбһӣбһҳбһ·бһ“бһҳбҹӮбһ“бһҹбһҳбҹ’бһҡбһ¶бһ”бҹӢ Fabricбҹ” ");

		if (connectorPresente) {
			mensaje.append("бһҡбһҖбһғбһҫбһү mod бһ—бҹ’бһҮбһ¶бһ”бҹӢ бһҠбҹӮбһӣбһ”бһ„бҹ’бһ бһ¶бһүбһҗбһ¶бһўбҹ’бһ“бһҖбһҖбҹҶбһ–бһ»бһ„бһ”бҹ’бһҡбһҫ mods Fabric бһ“бҹ…бһҖбҹ’бһ“бһ»бһ„бһ”бһҡбһ·бһҹбҹ’бһҗбһ¶бһ“ Forgeбҹ” ");
			mensaje.append("бһ–бһ·бһ“бһ·бһҸбҹ’бһҷ log бһҠбһҫбһҳбҹ’бһ”бһёбһҡбһҖ mod бһҠбҹӮбһӣбһ”бһ„бҹ’бһҖбһ”бһүбҹ’бһ бһ¶бҹ” ");
		}

		mensaje.append("AzureLib бһ“бһ·бһ„ GeckoLib бһҸбҹ’бһҡбһјбһңбһҸбҹӮбһ•бҹ’бһӮбһјбһ•бҹ’бһӮбһ„бһҮбһ¶бһҳбһҪбһҷбһңбҹҒбһ‘бһ·бһҖбһ¶бһҸбҹ’бһҡбһ№бһҳбһҸбҹ’бһҡбһјбһңбҹ” ");
		mensaje.append("бһ бҹ’бһӮбҹҒбһҳбһҳбһ·бһ“бһўбһ¶бһ…бһ•бҹ’бһ‘бһ»бһҖ mods бһ”бһ¶бһ“бһҠбҹ„бһҷбһҹбһ¶бһҡбһҖбҹҶбһ бһ»бһҹбһ“бҹҒбҹҮбҹ”");

		mensaje.append("</b>");
		return mensaje.toString();
	}

