	@Override
	public String errorRegistroSuscriptoresAutomaticos(String modId, String nombreClase, List<String> modsUbicacion) {
		StringBuilder mensaje = new StringBuilder("<b style='color:#" + config.obtenerColorError() + "'>");
		mensaje.append("бһҖбҹҶбһ бһ»бһҹбһ’бҹ’бһ„бһ“бҹӢбһ’бҹ’бһ„бһҡбҹ– бһ”бһҡбһ¶бһҮбҹҗбһҷбһҖбҹ’бһ“бһ»бһ„бһҖбһ¶бһҡбһ…бһ»бҹҮбһ”бһүбҹ’бһҮбһёбһўбҹ’бһ“бһҖбһ‘бһ‘бһҪбһӣбһҹбһүбҹ’бһүбһ¶бһҠбҹ„бһҷбһҹбҹ’бһңбҹҗбһҷбһ”бҹ’бһҡбһңбһҸбҹ’бһҸбһ·бһҹбһҳбҹ’бһҡбһ¶бһ”бҹӢ mod '").append(modId)
				.append("'. ");

		mensaje.append("бһҗбҹ’бһ“бһ¶бһҖбҹӢбһҠбҹӮбһӣбһҳбһ¶бһ“бһ”бһүбҹ’бһ бһ¶бҹ– <b>").append(nombreClase).append("</b>. ");

		if (!modsUbicacion.isEmpty()) {
			mensaje.append("бһҗбҹ’бһ“бһ¶бһҖбҹӢбһ“бҹҒбҹҮбһҳбһ¶бһ“бһ“бҹ…бһҖбҹ’бһ“бһ»бһ„бҹ– <b>");
			for (int i = 0; i < Math.min(modsUbicacion.size(), 3); i++) {
				mensaje.append(modsUbicacion.get(i));
				if (i < modsUbicacion.size() - 1 && i < 2)
					mensaje.append(", ");
			}
			if (modsUbicacion.size() > 3)
				mensaje.append(", бһ“бһ·бһ„бһ•бҹ’бһҹбҹҒбһ„бһ‘бҹҖбһҸ...");
			mensaje.append("</b>. ");
		}

		mensaje.append(
				"бһңбһ¶бһҖбһҫбһҸбһЎбһҫбһ„бһ“бҹ…бһ–бҹҒбһӣ mod бһҳбһҪбһҷбһ–бҹ’бһҷбһ¶бһҷбһ¶бһҳбһ…бһ»бҹҮбһ”бһүбҹ’бһҮбһёбһҗбҹ’бһ“бһ¶бһҖбҹӢбһҮбһ¶бһўбҹ’бһ“бһҖбһ‘бһ‘бһҪбһӣбһҹбһүбҹ’бһүбһ¶ бһ”бҹүбһ»бһ“бҹ’бһҸбҹӮбһҳбһ·бһ“бһўбһ¶бһ…бһ•бҹ’бһ‘бһ»бһҖбһҗбҹ’бһ“бһ¶бһҖбҹӢбһ”бһ¶бһ“бһҸбҹ’бһҡбһ№бһҳбһҸбҹ’бһҡбһјбһңбҹ” ");
		mensaje.append("<b>бһҹбһјбһҳбһ–бһ·бһ“бһ·бһҸбҹ’бһҷбһҖбҹҶбһ бһ»бһҹбһ•бҹ’бһҹбҹҒбһ„бҹ—бһ“бҹ…бһҖбҹ’бһ“бһ»бһ„ log бһ–бҹ’бһҡбҹ„бҹҮбһ”бһүбҹ’бһ бһ¶бһ–бһ·бһҸбһўбһ¶бһ…бһҹбҹ’бһҗбһ·бһҸбһ“бҹ…бһҖбһ“бҹ’бһӣбҹӮбһ„бһ•бҹ’бһҹбҹҒбһ„</b>бҹ”");
		mensaje.append("</b>");

		return mensaje.toString();
	}

