	@Override
	public String paso2_registro_suscriptores_automaticos(String modId, String nombreClase,
			List<String> modsUbicacion) {
		if (!modsUbicacion.isEmpty()) {
			StringBuilder paso = new StringBuilder(
					"бһҗбҹ’бһ“бһ¶бһҖбҹӢбһҠбҹӮбһӣбһҳбһ¶бһ“бһ”бһүбҹ’бһ бһ¶ <b>" + nombreClase + "</b> бһҳбһ¶бһ“бһ“бҹ…бһҖбҹ’бһ“бһ»бһ„бһҜбһҖбһҹбһ¶бһҡбһ‘бһ¶бҹҶбһ„бһ“бҹҒбҹҮбҹ– <b>");
			for (int i = 0; i < Math.min(modsUbicacion.size(), 3); i++) {
				paso.append(modsUbicacion.get(i));
				if (i < modsUbicacion.size() - 1 && i < 2)
					paso.append(", ");
			}
			if (modsUbicacion.size() > 3)
				paso.append(", бһ“бһ·бһ„бһ•бҹ’бһҹбҹҒбһ„бһ‘бҹҖбһҸ...");
			paso.append("</b>. ");
			paso.append("бһ”бҹ’бһҡбһҫбһҳбһ»бһҒбһ„бһ¶бһҡ <b>Arbol de Mods</b> бһҠбһҫбһҳбҹ’бһ”бһёбһ”бһүбҹ’бһҮбһ¶бһҖбҹӢбһҗбһ¶бһҜбһҖбһҹбһ¶бһҡбһҺбһ¶бһҠбҹӮбһӣбһҳбһ¶бһ“бһҗбҹ’бһ“бһ¶бһҖбҹӢбһ“бҹҒбҹҮ");
			return paso.toString();
		}
		return "бһҗбҹ’бһ“бһ¶бһҖбҹӢ <b>" + nombreClase + "</b> бһҳбһ·бһ“бһҸбҹ’бһҡбһјбһңбһ”бһ¶бһ“бһҡбһҖбһғбһҫбһүбһҖбҹ’бһ“бһ»бһ„ mod бһҺбһ¶бһҳбһҪбһҷбһ‘бҹҒбҹ” " + "бһҹбһјбһҳбһ–бһ·бһ“бһ·бһҸбҹ’бһҷбһҗбһ¶ mod <b>" + modId
				+ "</b> бһҸбҹ’бһҡбһјбһңбһ”бһ¶бһ“бһҠбҹҶбһЎбһҫбһ„бһҸбҹ’бһҡбһ№бһҳбһҸбҹ’бһҡбһјбһңбҹ” бһ”бҹ’бһҡбһҫ <b>Arbol de Mods</b> бһҠбһҫбһҳбҹ’бһ”бһёбһҮбһҪбһҷбһҡбһҖбһ”бһүбҹ’бһ бһ¶";
	}

