		sb.append("</b>");

		sb.append("бһҗбҹ’бһ“бһ¶бһҖбҹӢбһҠбҹӮбһӣбһ–бһ¶бһҖбҹӢбһ–бҹҗбһ“бҹ’бһ’бһӮбһә <b>").append(claseReceptora).append("</b>бҹ” ");
