	@Override
	public String errorConfiguracionServicio(String clase, List<String> mods) {
		StringBuilder sb = new StringBuilder();
		sb.append("<b style='color:#").append(config.obtenerColorError()).append("'>");
		sb.append("бһҖбҹҶбһ бһ»бһҹбһ’бҹ’бһ„бһ“бҹӢбһ’бҹ’бһ„бһҡ: бһҳбһ·бһ“бһўбһ¶бһ…бһ•бҹ’бһ‘бһ»бһҖбһҹбҹҒбһңбһ¶бһҖбһҳбҹ’бһҳ modlauncher (IDependencyLocator) бһ”бһ¶бһ“бҹ”<br>");
		sb.append("рҹ”№ <b>бһҗбҹ’бһ“бһ¶бһҖбҹӢбһҳбһ¶бһ“бһ”бһүбҹ’бһ бһ¶:</b> <code>").append(clase).append("</code><br>");

		if (mods != null && !mods.isEmpty()) {
			sb.append("рҹ”ё <b>бһҳбҹүбһјбһҠбһҠбҹӮбһӣбһҡбһ„бһ•бһӣбһ”бҹүбҹҮбһ–бһ¶бһӣбҹӢ:</b> ").append(String.join(", ", mods)).append("<br>");
		} else {
			sb.append("рҹ”ё <b>бһҳбһ·бһ“бһўбһ¶бһ…бһҖбҹҶбһҺбһҸбҹӢбһҳбҹүбһјбһҠбһ”бһ¶бһ“бҹ”</b> бһҹбһјбһҳбһ–бһ·бһ“бһ·бһҸбҹ’бһҷбһҳбҹүбһјбһҠбһҗбҹ’бһҳбһё бһ¬бһҳбҹүбһјбһҠбһҠбҹӮбһӣбһҖбҹҶбһ–бһ»бһ„бһўбһ—бһ·бһңбһҢбҹ’бһҚбҹ”<br>");
		}

		sb.append(
				"рҹ”ё <b>бһҳбһјбһӣбһ бҹҒбһҸбһ»:</b> бһҜбһҖбһҹбһ¶бһҡ <code>META-INF/services/...</code> бһҡбһ”бһҹбҹӢбһҳбҹүбһјбһҠбһҒбһјбһ… бһ¬бһҳбһ·бһ“бһҶбһ”бһӮбҹ’бһ“бһ¶бһҮбһ¶бһҳбһҪбһҷ Forge/NeoForge бһ¬бһҮбһ¶бһңбһҫбһҹбһ·бһ“бһҒбһ»бһҹбҹ”<br>");
		sb.append(
				"рҹ”ё <b>бһ•бһӣбһңбһ·бһ”бһ¶бһҖ:</b> Forge/NeoForge бһҳбһ·бһ“бһўбһ¶бһ…бһ…бһ»бҹҮбһҲбҹ’бһҳбҹ„бҹҮ dependency бһ”бһ¶бһ“ бһҠбҹӮбһӣбһ”бһҺбҹ’бһҠбһ¶бһӣбһІбҹ’бһҷбһ бҹ’бһӮбҹҒбһҳбһҳбһ·бһ“бһўбһ¶бһ…бһ…бһ¶бһ”бҹӢбһ•бҹ’бһҸбһҫбһҳбһ”бһ¶бһ“бҹ”<br>");
		sb.append("рҹ”ё <b>бһҠбҹҶбһҺбҹ„бҹҮбһҹбҹ’бһҡбһ¶бһҷ:</b> бһ’бҹ’бһңбһҫбһ”бһ…бҹ’бһ…бһ»бһ”бҹ’бһ”бһ“бҹ’бһ“бһ—бһ¶бһ– бһҠбҹҶбһЎбһҫбһ„бһЎбһҫбһ„бһңбһ·бһү бһ¬бһӣбһ»бһ”бһҳбҹүбһјбһҠбһҠбҹӮбһӣбһҳбһ¶бһ“бһ”бһүбҹ’бһ бһ¶бҹ” ");
		sb.append("бһ”бһҫбһўбҹ’бһ“бһҖбһ”бҹ’бһҡбһҫбһҳбҹүбһјбһҠбһўбһ—бһ·бһңбһҢбҹ’бһҚ бһҹбһјбһҳбһ”бҹ’бһҡбһ¶бһҖбһҠбһҗбһ¶бһңбһ¶бһҸбҹ’бһҡбһјбһңбһ”бһ¶бһ“бһҖбҹҶбһ–бһ„бҹӢ compile бһҹбһҳбҹ’бһҡбһ¶бһ”бҹӢбһңбһҫбһҹбһ·бһ“бһҸбҹ’бһҡбһ№бһҳбһҸбҹ’бһҡбһјбһңбҹ”");
		sb.append("</b>");
		return sb.toString();
	}

