	@Override
	public String mensajeAyudar() {
		String iconoCompartir = Statics.carpeta.resolve("imagenes").resolve("boton_compartir_icon.png").toAbsolutePath()
				.toUri().toString();

		String colorTexto = Config.obtenerInstancia().obtenerColorInfo();

		return "" + "<div style='color:" + colorTexto + ";'>" + "  <strong>бһҸбҹ’бһҡбһјбһңбһҖбһ¶бһҡбһҮбҹҶбһ“бһҪбһҷ?</strong><br>"
				+ "  бһ”бҹ’бһҡбһҹбһ·бһ“бһ”бһҫбһўбҹ’бһ“бһҖбһҳбһ·бһ“бһҠбһ№бһ„бһҡбһ”бҹҖбһ”бһҠбҹ„бҹҮбһҹбҹ’бһҡбһ¶бһҷ бһўбҹ’бһ“бһҖбһўбһ¶бһ…бһ‘бһ‘бһҪбһӣбһҮбҹҶбһ“бһҪбһҷбһҸбһ¶бһҳбһ”бһҺбҹ’бһҠбһ¶бһүбһҹбһ„бҹ’бһӮбһҳбҹ” " + "  бһ”бҹ’бһҡбһҫбһ”бҹҠбһјбһҸбһ»бһ„ <img src='"
				+ iconoCompartir + "' alt='бһ…бҹӮбһҖбһҡбҹҶбһӣбҹӮбһҖ' style='height:12px;vertical-align:middle;'/> "
				+ "  <strong>бһ…бҹӮбһҖбһҡбҹҶбһӣбҹӮбһҖ</strong> бһҠбһҫбһҳбҹ’бһ”бһёбһ•бҹ’бһүбһҫбһҖбҹҶбһҺбһҸбҹӢбһ бҹҒбһҸбһ» бһ“бһ·бһ„бһӣбһ‘бҹ’бһ’бһ•бһӣбҹ” "
				+ "  бһ”бҹ’бһҡбһҹбһ·бһ“бһ”бһҫбһўбҹ’бһ“бһҖбһҮбһ¶бһўбҹ’бһ“бһҖбһ”бһ„бҹ’бһҖбһҫбһҸ modpack бһўбҹ’бһ“бһҖбһўбһ¶бһ…бһҖбҹӮбһҹбһҳбҹ’бһҡбһҪбһӣ <code>crash_detector/plantilla.htm</code> "
				+ "  бһҠбһҫбһҳбҹ’бһ”бһёбһҖбҹҶбһҺбһҸбҹӢбһҸбҹҶбһҺбһ•бҹ’бһ‘бһ¶бһӣбҹӢбһҒбҹ’бһӣбһҪбһ“бҹ”" + "</div>";
	}

