	@Override
	public String errorMetodoAbstractoNoImplementadoDetallado(String clase, String metodo, String interfaz,
			String origen) {
		String colorError = config.obtenerColorError();
		StringBuilder sb = new StringBuilder();
		sb.append("<b style='color:#").append(colorError).append(";'>").append("бһҗбҹ’бһ“бһ¶бһҖбҹӢ <code>").append(clase)
				.append("</code> бһҳбһ·бһ“бһ”бһ¶бһ“бһўбһ“бһ»бһңбһҸбҹ’бһҸ method бһҠбҹӮбһӣбһҸбҹ’бһҡбһјбһңбһҖбһ¶бһҡбҹ–<br>").append("<code>").append(metodo)
				.append("</code><br>").append("бһ–бһё interface <code>").append(interfaz).append("</code>.");

		if (!origen.isEmpty()) {
			sb.append("<br><br>бһҳбҹүбһјбһҠ бһ¬бһҜбһҖбһҹбһ¶бһҡбһҠбҹӮбһӣбһӮбһҪбһҡбһҹбһ„бҹ’бһҹбҹҗбһҷбҹ– <code>").append(origen).append("</code>.");
		}

		sb.append("</b>");
		return sb.toString();
	}

