	@Override
	public String necesitasInstalarCfr() {
		String sistema = System.getProperty("os.name").toLowerCase();
		StringBuilder mensaje = new StringBuilder();
		mensaje.append("<html>").append("бһўбҹ’бһ“бһҖбһҸбҹ’бһҡбһјбһңбһҠбҹҶбһЎбһҫбһ„ CFR (Class File Reader) бһҠбһҫбһҳбҹ’бһ”бһёбһ”бҹ’бһҡбһҫбһҳбһ»бһҒбһ„бһ¶бһҡбһ“бҹҒбҹҮбҹ”<br><br>");

		if (sistema.contains("linux") || sistema.contains("netbsd") || sistema.contains("freebsd")) {
			mensaje.append("бһ“бҹ…бһӣбһҫ Linux, NetBSD бһ¬ FreeBSD бһўбҹ’бһ“бһҖбһўбһ¶бһ…бһҠбҹҶбһЎбһҫбһ„ CFR бһҸбһ¶бһҳ package manager бһҡбһ”бһҹбҹӢбһўбҹ’бһ“бһҖбҹ”<br>").append(
					"бһҹбҹ’бһңбҹӮбһ„бһҡбһҖ package бһ“бҹ…бһ‘бһёбһ“бҹҒбҹҮбҹ– <a href=\"https://pkgs.org/search/?q=cfr\">https://pkgs.org/search/?q=cfr</a><br><br>");
		}

		mensaje.append("бһҮбһ¶бһҮбһҳбҹ’бһҡбһҫбһҹбһ•бҹ’бһҹбҹҒбһ„ бһўбҹ’бһ“бһҖбһўбһ¶бһ…бһ‘бһ¶бһүбһҷбһҖбһҖбҹҶбһҺбҹӮбһҠбҹӮбһӣбһ”бһ¶бһ“бһҖбҹӮбһ”бҹ’бһҡбҹӮбһҠбҹӮбһӣ FabricMC бһ”бҹ’бһҡбһҫбһ–бһёбҹ–<br>")
				.append("<a href=\"https://maven.fabricmc.net/net/fabricmc/cfr/0.2.2/cfr-0.2.2.jar\">")
				.append("https://maven.fabricmc.net/net/fabricmc/cfr/0.2.2/cfr-0.2.2.jar</a><br><br>")
				.append("бһҡбһҖбҹ’бһҹбһ¶бһ‘бһ»бһҖбһңбһ¶бһ“бҹ…бһҖбҹ’бһ“бһ»бһ„бһҗбһҸбһҒбһ¶бһ„бһҖбҹ’бһҡбҹ„бһҳбҹ–<br>").append("<b>")
				.append(new java.io.File(com.asbestosstar.crashdetector.Statics.carpeta_mundial_como_archivo, "cfr/")
						.getAbsolutePath())
				.append("</b><br><br>")
				.append("вҡ пёҸ <b>бһҹбҹҶбһҒбһ¶бһ“бҹӢбҹ–</b> бһ”бһ“бҹ’бһ‘бһ¶бһ”бҹӢбһ–бһёбһҠбҹҶбһЎбһҫбһ„ CFR бһўбҹ’бһ“бһҖбһҸбҹ’бһҡбһјбһңбһ…бһ¶бһ”бҹӢбһ•бҹ’бһҸбһҫбһҳ mod бһЎбһҫбһ„бһңбһ·бһү бһҠбһҫбһҳбҹ’бһ”бһёбһІбҹ’бһҷбһңбһ¶бһҸбҹ’бһҡбһјбһңбһ”бһ¶бһ“бһҹбҹ’бһӮбһ¶бһӣбҹӢбҹ”")
				.append("</html>");
		return mensaje.toString();
	}

