	@Override
	public String mensajeIndependenteFlywheel(Set<String> mods) {
		StringBuilder listaMods = new StringBuilder();
		if (!mods.isEmpty()) {
			for (String mod : mods) {
				listaMods.append("<li>").append(mod).append("</li>");
			}
		}

		String mensaje = "<b style='color:#" + Config.obtenerInstancia().obtenerColorError() + "'>"
				+ "бһ”бһ¶бһ“бһҡбһҖбһғбһҫбһүбһҖбһ¶бһҡбһ”бҹ’бһҡбһҫбһ”бҹ’бһҡбһ¶бһҹбҹӢ <i>Independiente Flywheel</i>бҹ”</b>"
				+ "<p><b>Independiente Flywheel бһӮбһәбһ…бһ¶бһҹбҹӢ (deprecated)</b> бһ бһҫбһҷбһҳбһ·бһ“бһӮбһҪбһҡбһ”бҹ’бһҡбһҫбһ“бҹ…бһҖбҹ’бһ“бһ»бһ„бһҖбҹҶбһҺбҹӮбһ‘бҹҶбһ“бһҫбһ”бһ‘бҹҒбҹ”</p>"
				+ "<p>бһҖбҹҶбһҺбҹӮбһҗбҹ’бһҳбһёбҹ—бһ“бҹғ <b>Create</b> <b>бһҳбһ¶бһ“ Flywheel бһҡбһҪбһ…бһ бһҫбһҷ</b> бһҠбһјбһ…бҹ’бһ“бҹҒбҹҮбһҖбһ¶бһҡбһҠбҹҶбһЎбһҫбһ„бһңбһ¶бһҠбҹ„бһҷбһЎбҹӮбһҖ "
				+ "бһ“бһ№бһ„бһ”бһ„бҹ’бһҖбһ”бһүбҹ’бһ бһ¶бһ—бһ¶бһ–бһҶбһ”бһӮбҹ’бһ“бһ¶ бһ“бһ·бһ„бһҖбҹҶбһ бһ»бһҹбһ–бҹҒбһӣбһ•бҹ’бһ‘бһ»бһҖбҹ”</p>" + "<p>бһҳбҹүбһјбһҠбһҒбҹ’бһӣбҹҮбһҠбҹӮбһӣбһ–бһ№бһ„бһ•бҹ’бһўбҹӮбһҖбһӣбһҫ Independiente Flywheel бһўбһ¶бһ… "
				+ "<b>бһҳбһ·бһ“бһҠбҹҶбһҺбһҫбһҡбһҖбһ¶бһҡ</b> бһ¬ <b>бһҠбҹҶбһҺбһҫбһҡбһҖбһ¶бһҡбһҳбһ·бһ“бһҹбҹ’бһҗбһ·бһҡбһ—бһ¶бһ–</b>бҹ” " + "бһҖбҹ’бһ“бһ»бһ„бһҖбһҡбһҺбһёбһҒбҹ’бһӣбҹҮ бһўбһ¶бһ…бһҠбҹҶбһҺбһҫбһҡбһҖбһ¶бһҡбһ”бһ¶бһ“ бһ”бҹ’бһҡбһҹбһ·бһ“бһ”бһҫ "
				+ "<b>бһҖбҹӮбһ”бҹ’бһҡбҹӮбһҜбһҖбһҹбһ¶бһҡ <code>mods.toml</code> бһҠбҹ„бһҷбһҠбҹғ</b> бһҠбһҫбһҳбҹ’бһ”бһёбһҖбҹӮбһҹбһҳбҹ’бһҡбһҪбһӣбһҖбҹҶбһҺбҹӮ "
				+ "бһ”бҹүбһ»бһ“бҹ’бһҸбҹӮбһ“бҹҒбҹҮ <b>бһҳбһ·бһ“бһҸбҹ’бһҡбһјбһңбһ”бһ¶бһ“бһҺбҹӮбһ“бһ¶бҹҶ</b> бһ‘бҹҒбҹ”</p>"
				+ (mods.isEmpty() ? ""
						: "<p><b>бһҳбҹүбһјбһҠбһҠбҹӮбһӣбһ”бһ¶бһ“бһҡбһҖбһғбһҫбһүбһҠбҹӮбһӣбһ–бһ¶бһҖбҹӢбһ–бҹҗбһ“бҹ’бһ’бһ“бһ№бһ„ Flywheel:</b></p><ul>" + listaMods.toString() + "</ul>")
				+ "<p>бһҠбҹҶбһҺбҹ„бҹҮбһҹбҹ’бһҡбһ¶бһҷбһҠбҹӮбһӣбһ”бһ¶бһ“бһҺбҹӮбһ“бһ¶бҹҶбһӮбһә <b>бһӣбһ»бһ” Independiente Flywheel</b> бһ бһҫбһҷбһ”бҹ’бһҡбһҫбһҸбҹӮ "
				+ "бһҖбҹҶбһҺбҹӮбһҠбҹӮбһӣбһҳбһ¶бһ“бһҖбҹ’бһ“бһ»бһ„ Create бһ”бҹүбһ»бһҺбҹ’бһҺбҹ„бҹҮбҹ”</p>";

		return mensaje;
	}

