	@Override
	public String mensajeAccesoDenegadoBackupConfig(String origen, String backup) {
		String src = origen == null || origen.isEmpty() ? "бһҳбһ·бһ“бһҹбҹ’бһӮбһ¶бһӣбҹӢ" : origen;
		String dst = backup == null || backup.isEmpty() ? "бһҳбһ·бһ“бһҹбҹ’бһӮбһ¶бһӣбҹӢ" : backup;

		return "<b style='color:#" + Config.obtenerInstancia().obtenerColorError() + "'>"
				+ "бһ”бһ¶бһ“бһҖбһҫбһҸбһҳбһ¶бһ“бһҖбҹҶбһ бһ»бһҹбһҹбһ·бһ‘бҹ’бһ’бһ·бһ–бҹҒбһӣбһ”бһ„бҹ’бһҖбһҫбһҸбһ…бһҳбҹ’бһӣбһ„бһ”бһҳбҹ’бһҡбһ»бһ„бһҜбһҖбһҹбһ¶бһҡбһҖбҹҶбһҺбһҸбҹӢбҹ”</b>" + "<p><b>бһҜбһҖбһҹбһ¶бһҡбһҠбһҫбһҳ:</b> " + src + "</p>"
				+ "<p><b>бһҜбһҖбһҹбһ¶бһҡбһ”бһҳбҹ’бһҡбһ»бһ„:</b> " + dst + "</p>"
				+ "<p>бһ”бҹ’бһҡбһ–бҹҗбһ“бҹ’бһ’бһ”бҹ’бһҡбһҸбһ·бһ”бһҸбҹ’бһҸбһ·бһҖбһ¶бһҡбһ”бһ¶бһ“бһ‘бһ”бҹӢбһҹбҹ’бһҖбһ¶бһҸбҹӢбһҖбһ¶бһҡбһ…бһјбһӣбһ”бҹ’бһҡбһҫбһ“бҹ…бһ–бҹҒбһӣбһҡбһҖбҹ’бһҹбһ¶бһ‘бһ»бһҖбһҜбһҖбһҹбһ¶бһҡбҹ”</p>"
				+ "<p><b>бһҮбһ¶бһ’бһҳбҹ’бһҳбһҸбһ¶бһҖбһҫбһҸбһЎбһҫбһ„бһҠбҹ„бһҷбһҹбһ¶бһҡ:</b></p><ul>" + "<li>бһҹбһ·бһ‘бҹ’бһ’бһ·бһҳбһ·бһ“бһӮбҹ’бһҡбһ”бҹӢбһӮбҹ’бһҡбһ¶бһ“бҹӢбһ“бҹ…бһҖбҹ’бһ“бһ»бһ„бһҗбһҸбҹ”</li>"
				+ "<li>бһҜбһҖбһҹбһ¶бһҡбһҸбҹ’бһҡбһјбһңбһ”бһ¶бһ“бһҖбҹҶбһҺбһҸбҹӢбһҮбһ¶ read-onlyбҹ”</li>" + "<li>бһҖбһҳбҹ’бһҳбһңбһ·бһ’бһёбһ•бҹ’бһҹбҹҒбһ„бһҖбҹҶбһ–бһ»бһ„бһ”бҹ’бһҡбһҫбһҜбһҖбһҹбһ¶бһҡбҹ”</li>" + "</ul>"
				+ "<p><b>бһҖбһ¶бһҡбһҺбҹӮбһ“бһ¶бҹҶ:</b></p><ul>" + "<li>бһ–бһ·бһ“бһ·бһҸбҹ’бһҷбһҹбһ·бһ‘бҹ’бһ’бһ·бһ“бҹ…бһҖбҹ’бһ“бһ»бһ„бһҗбһҸ <b>config</b>бҹ”</li>"
				+ "<li>бһ”бһ·бһ‘бһҖбһҳбҹ’бһҳбһңбһ·бһ’бһёбһҠбҹӮбһӣбһўбһ¶бһ…бһҖбҹҶбһ–бһ»бһ„бһ”бҹ’бһҡбһҫбһҜбһҖбһҹбһ¶бһҡбҹ”</li>"
				+ "<li>бһҹбһ¶бһҖбһӣбҹ’бһ”бһ„бһҠбҹҶбһҺбһҫбһҡбһҖбһ¶бһҡ launcher бһ¬ Minecraft бһҮбһ¶ administratorбҹ”</li>" + "</ul>";
	}

