	@Override
	public String mensajeVersionInvalida(String version, String ubicacion) {
		String v = (version == null || version.isEmpty()) ? "бһҳбһ·бһ“бһҹбҹ’бһӮбһ¶бһӣбҹӢ" : version;
		String u = (ubicacion == null || ubicacion.isEmpty()) ? "бһҳбһ·бһ“бһўбһ¶бһ…бһҡбһҖбһғбһҫбһүбһҳбҹүбһјбһҠ" : ubicacion;
		return "<b style='color:#" + Config.obtenerInstancia().obtenerColorError() + "'>"
				+ "бһҡбһҖбһғбһҫбһүбһҖбҹҶбһҺбҹӮбһҳбһ·бһ“бһҸбҹ’бһҡбһ№бһҳбһҸбҹ’бһҡбһјбһңбһ“бҹғбһҳбҹүбһјбһҠбҹ”</b>" + "<p>бһҖбҹҶбһҺбҹӮ <b>" + v
				+ "</b> бһҳбһ·бһ“бһҸбҹ’бһҡбһјбһңбһҸбһ¶бһҳбһ‘бҹ’бһҡбһ„бҹӢбһ‘бҹ’бһҡбһ¶бһҷ SemVer бһҸбҹ’бһҡбһ№бһҳбһҸбҹ’бһҡбһјбһңбҹ”</p>"
				+ "<p>бһҖбҹҶбһ бһ»бһҹбһ”бһ„бҹ’бһ бһ¶бһүбһҗбһ¶ pre-release бһ‘бһ‘бҹҒ (бһ”бһүбҹ’бһ…бһ”бҹӢбһҠбҹ„бһҷ '+')бҹ”</p>" + "<p><b>бһҳбҹүбһјбһҠбһҠбҹӮбһӣбһ–бһ¶бһҖбҹӢбһ–бҹҗбһ“бҹ’бһ’:</b><br>" + u
				+ "</p>" + "<p><b>бһҠбҹҶбһҺбҹ„бҹҮбһҹбҹ’бһҡбһ¶бһҷбһҺбҹӮбһ“бһ¶бҹҶ:</b></p><ul>" + "<li>бһҖбҹӮбһ”бҹ’бһҡбҹӮбһҜбһҖбһҹбһ¶бһҡбһҳбҹүбһјбһҠ бһ“бһ·бһ„бһҖбҹҶбһҺбҹӮбһІбҹ’бһҷбһҸбҹ’бһҡбһ№бһҳбһҸбҹ’бһҡбһјбһңбҹ”</li>"
				+ "<li>бһӣбһ»бһ” '+' бһ…бһ»бһ„бһҖбҹ’бһҡбҹ„бһҷ бһ”бҹ’бһҡбһҹбһ·бһ“бһ”бһҫбһӮбҹ’бһҳбһ¶бһ“ metadataбҹ”</li>" + "<li>бһ’бҹ’бһңбһҫбһ”бһ…бҹ’бһ…бһ»бһ”бҹ’бһ”бһ“бҹ’бһ“бһ—бһ¶бһ–бһҳбҹүбһјбһҠбһ‘бҹ…бһҖбҹҶбһҺбҹӮбһҗбҹ’бһҳбһёбҹ”</li>"
				+ "</ul>";
	}

