	@Override
	public String mensajeRenderOutlineRendertypeInvalido(boolean enchantDetectado) {
		String base = "<b style='color:#" + Config.obtenerInstancia().obtenerColorError() + "'>"
				+ "бһҳбҹүбһјбһҠбһҳбһҪбһҷбһ”бһ¶бһ“бһ”бҹ’бһҡбһҫ outline бһҮбһ¶бһҳбһҪбһҷ RenderType бһҳбһ·бһ“бһҸбҹ’бһҡбһ№бһҳбһҸбҹ’бһҡбһјбһңбҹ”</b>"
				+ "<p><code>Can't render an outline for this rendertype!</code></p>";

		if (enchantDetectado) {
			base += "<p>бһ”бһ¶бһ“бһҡбһҖбһғбһҫбһү mod enchant-outlineбҹ”</p>" + "<p><b>бһҠбҹҶбһҺбҹ„бҹҮбһҹбҹ’бһҡбһ¶бһҷ:</b> бһӣбһ»бһ” бһ¬бһ’бҹ’бһңбһҫбһ”бһ…бҹ’бһ…бһ»бһ”бҹ’бһ”бһ“бҹ’бһ“бһ—бһ¶бһ–бһҳбҹүбһјбһҠбҹ”</p>";
		} else {
			base += "<p>бһ–бһ¶бһҖбҹӢбһ–бҹҗбһ“бҹ’бһ’бһ“бһ№бһ„бһҳбҹүбһјбһҠ renderingбҹ”</p>"
					+ "<p><b>бһҠбҹҶбһҺбҹ„бҹҮбһҹбҹ’бһҡбһ¶бһҷ:</b> бһ’бҹ’бһңбһҫбһ”бһ…бҹ’бһ…бһ»бһ”бҹ’бһ”бһ“бҹ’бһ“бһ—бһ¶бһ– бһ¬бһ”бһ·бһ‘бһҳбҹүбһјбһҠбһҳбҹ’бһҸбһ„бһҳбһҪбһҷбҹ”</p>";
		}

		return base;
	}

