	@Override
	public String mensajeRestriccionesDependenciaNoCumplidas(String cantidad, List<String[]> conflictos) {
		String color = Config.obtenerInstancia().obtenerColorError();

		String mensajeBase = "<span style='color:#" + color + "'>бһҡбһҖбһғбһҫбһү </span>" + cantidad + "<span style='color:#"
				+ color + "'> бһ”бһүбҹ’бһ бһ¶ dependencyбҹ”</span><br><br>";

		StringBuilder listaDetalle = new StringBuilder();
		if (conflictos != null && !conflictos.isEmpty()) {
			listaDetalle.append("<span style='color:#").append(color).append("'>бһҜбһҖбһҹбһ¶бһҡбһҠбҹӮбһӣбһҳбһ¶бһ“бһ”бһүбҹ’бһ бһ¶:</span><br><ul>");
			for (String[] par : conflictos) {
				listaDetalle.append("<li><span style='color:#").append(color).append("'>бһҜбһҖбһҹбһ¶бһҡ: </span>").append(par[1])
						.append("<br><span style='color:#").append(color).append("'>бһҸбҹ’бһҡбһјбһңбһҖбһ¶бһҡ: </span>").append(par[0])
						.append("</li>");
			}
			listaDetalle.append("</ul><br>");
		}

		String instrucciones = "<span style='color:#" + color + "'>" + "бһңбһ¶бһҖбһҫбһҸбһЎбһҫбһ„бһ–бҹҒбһӣбһҳбҹүбһјбһҠбһҸбҹ’бһҡбһјбһңбһҖбһ¶бһҡбһҖбҹҶбһҺбҹӮбһҒбһ»бһҹбһӮбҹ’бһ“бһ¶бҹ”<br><br>"
				+ "<b>бһҠбҹҶбһҺбҹ„бҹҮбһҹбҹ’бһҡбһ¶бһҷ:</b><ul>" + "<li>бһ’бҹ’бһңбһҫбһ”бһ…бҹ’бһ…бһ»бһ”бҹ’бһ”бһ“бҹ’бһ“бһ—бһ¶бһ– бһ¬бһӣбһ»бһ”бһҳбҹүбһјбһҠбһҠбҹӮбһӣбһҳбһ¶бһ“бһ”бһүбҹ’бһ бһ¶бҹ”</li>"
				+ "<li>бһўбһ¶бһ…бһҖбҹӮ mods.toml бһҠбҹ„бһҷбһҠбҹғ (бһ бһ¶бһ“бһ·бһ—бҹҗбһҷбһҒбҹ’бһ–бһҹбҹӢ)бҹ”</li>" + "</ul></span>";

		return mensajeBase + listaDetalle.toString() + instrucciones;
	}

	@Override
	public String mensajeRestriccionesDependenciaNoCumplidas(String cantidad,
			Map<String, List<String>> conflictosPorMod) {

		String color = Config.obtenerInstancia().obtenerColorError();

		String mensajeBase = "<span style='color:#" + color + "'>бһҡбһҖбһғбһҫбһү </span>" + cantidad + "<span style='color:#"
				+ color + "'> бһ”бһүбҹ’бһ бһ¶ dependencyбҹ”</span><br><br>";

		StringBuilder listaDetalle = new StringBuilder();
		if (conflictosPorMod != null && !conflictosPorMod.isEmpty()) {
			listaDetalle.append("<span style='color:#").append(color).append("'>бһҳбҹүбһјбһҠ бһ“бһ·бһ„ dependency:</span><br><ul>");

			for (Map.Entry<String, List<String>> entry : conflictosPorMod.entrySet()) {
				listaDetalle.append("<li><b>").append(entry.getKey()).append("</b><ul>");
				for (String dep : entry.getValue()) {
					listaDetalle.append("<li>").append(dep).append("</li>");
				}
				listaDetalle.append("</ul></li>");
			}
			listaDetalle.append("</ul><br>");
		} else {
			listaDetalle.append("<span style='color:#").append(color).append("'>бһҳбһ·бһ“бһўбһ¶бһ…бһҖбҹҶбһҺбһҸбҹӢбһҜбһҖбһҹбһ¶бһҡбҹ”</span><br>");
		}

		String instrucciones = "<span style='color:#" + color + "'>" + "бһ”бһүбҹ’бһ бһ¶бһ“бҹҒбҹҮбһҖбһҫбһҸбһЎбһҫбһ„бһҠбҹ„бһҷ JarInJar conflictбҹ”<br><br>"
				+ "<b>бһҠбҹҶбһҺбҹ„бҹҮбһҹбҹ’бһҡбһ¶бһҷ:</b><ul>" + "<li>бһ’бҹ’бһңбһҫбһ”бһ…бҹ’бһ…бһ»бһ”бҹ’бһ”бһ“бҹ’бһ“бһ—бһ¶бһ–бһҳбҹүбһјбһҠбһ‘бһ¶бҹҶбһ„бһўбһҹбҹӢбҹ”</li>"
				+ "<li>бһҖбҹӮ .jar бһ”бҹ’бһҡбһҹбһ·бһ“бһ”бһҫбһ…бһ¶бҹҶбһ”бһ¶бһ…бҹӢ (бһ бһ¶бһ“бһ·бһ—бҹҗбһҷ)бҹ”</li>" + "</ul></span>";

		return mensajeBase + listaDetalle.toString() + instrucciones;
	}

