	@Override
	public String mensajeItemNoExiste(String itemFaltante, String namespace) {
		String itemHtml = itemFaltante == null || itemFaltante.isEmpty() ? "(бһҳбһ·бһ“бһҹбҹ’бһӮбһ¶бһӣбҹӢ)" : itemFaltante;
		String namespaceHtml = namespace == null || namespace.isEmpty() ? "(бһҳбһ·бһ“бһҹбҹ’бһӮбһ¶бһӣбҹӢ)" : namespace;

		return "<b style='color:#" + Config.obtenerInstancia().obtenerColorError() + "'>"
				+ "бһ”бһ¶бһ“бһ–бҹ’бһҷбһ¶бһҷбһ¶бһҳбһ”бҹ’бһҡбһҫбһ’бһ¶бһҸбһ»бһҠбҹӮбһӣбһҳбһ·бһ“бһҳбһ¶бһ“бҹ”</b>" + "<p>бһ”бҹ’бһҡбһңбһҸбҹ’бһҸбһ·бһҖбҹҶбһҺбһҸбҹӢбһҸбҹ’бһҡбһ¶ (Log) бһҳбһ¶бһ“бһ”бһ“бҹ’бһ‘бһ¶бһҸбҹӢ <b>Item: " + itemHtml
				+ " does not exist</b>бҹ”</p>"
				+ "<p>бһҮбһ¶бһ’бһҳбҹ’бһҳбһҸбһ¶ бһ“бҹҒбҹҮбһҳбһ¶бһ“бһ“бҹҗбһҷбһҗбһ¶ <b>datapack</b>, <b>mod</b> бһ¬ <b>бһҖбһ¶бһҡбһҖбҹҶбһҺбһҸбҹӢбһҡбһ…бһ“бһ¶бһҹбһҳбҹ’бһ–бҹҗбһ“бҹ’бһ’</b> бһҒбҹ’бһӣбҹҮ "
				+ "бһҖбҹҶбһ–бһ»бһ„бһҷбҹ„бһ„бһ‘бҹ…бһӣбһҫбһ’бһ¶бһҸбһ»бһҠбҹӮбһӣбһҳбһ·бһ“бһҳбһ¶бһ“бһ“бҹ…бһҖбҹ’бһ“бһ»бһ„бһ бҹ’бһӮбҹҒбһҳбҹ”</p>" + "<p><b>бһўбҹ’бһңбһёбһҠбҹӮбһӣбһҸбҹ’бһҡбһјбһңбһ–бһ·бһ“бһ·бһҸбҹ’бһҷбҹ–</b></p>" + "<ul>"
				+ "<li>бһ–бһ·бһ“бһ·бһҸбҹ’бһҷбһҳбһҫбһӣбһҗбһ¶бһҸбһҫбһўбҹ’бһ“бһҖбһ”бһ¶бһ“бһҠбҹҶбһЎбһҫбһ„ mod бһҠбҹӮбһӣбһӮбһҪбһҡбһҸбҹӮбһ•бҹ’бһҸбһӣбҹӢбһ’бһ¶бһҸбһ» <b>" + itemHtml + "</b> бһ¬бһ“бҹ…бҹ”</li>"
				+ "<li>бһ”бҹ’бһҡбһҹбһ·бһ“бһ”бһҫбһҳбһ¶бһ“ бһңбһ¶бһўбһ¶бһ…бһҮбһ¶ <b>бһҖбҹҶбһҺбҹӮбһҳбһ·бһ“бһҸбҹ’бһҡбһ№бһҳбһҸбҹ’бһҡбһјбһң</b> бһ’бһ¶бһҸбһ»бһҸбҹ’бһҡбһјбһңбһ”бһ¶бһ“бһ•бҹ’бһӣбһ¶бһҹбҹӢбһ”бҹ’бһҸбһјбһҡ бһ¬бһӣбһ»бһ”бһ…бҹ„бһӣ "
				+ "бһ¬ mod бһ“бҹ„бҹҮбһҳбһ¶бһ“бһ”бһүбҹ’бһ бһ¶ бһ бһҫбһҷбһӮбһҪбһҡбһҸбҹӮбһҠбһҖбһңбһ¶бһ…бҹҒбһүбҹ”</li>"
				+ "<li>бһ”бҹ’бһҡбһҹбһ·бһ“бһ”бһҫбһўбҹ’бһ“бһҖбһҳбһ·бһ“бһҳбһ¶бһ“ mod бһ“бҹ„бҹҮбһ‘бҹҒ бһҹбһјбһҳбһ–бҹ’бһҷбһ¶бһҷбһ¶бһҳ <b>бһҠбҹҶбһЎбһҫбһ„бһңбһ¶</b>бҹ”</li>" + "</ul>"
				+ "<p><b>бһҠбһҫбһҳбҹ’бһ”бһёбһҠбһ№бһ„бһҗбһ¶ mod бһ¬ datapack бһҺбһ¶бһҠбҹӮбһӣбһҖбҹҶбһ–бһ»бһ„бһҹбҹ’бһ“бһҫбһҹбһ»бҹҶбһ’бһ¶бһҸбһ»бһ“бҹ„бҹҮбҹ–</b></p>" + "<ul>"
				+ "<li>бһ”бҹ’бһҡбһҫбһ§бһ”бһҖбһҡбһҺбҹҚ <b>grepr</b> бһ“бҹ…бһҖбҹ’бһ“бһ»бһ„бһҡбһ”бһ¶бһҡбһ…бҹҶбһ бҹҖбһ„бҹ”</li>" + "<li><b>бһҖбһ»бҹҶ</b> бһҮбҹ’бһҡбһҫбһҹбһҡбһҫбһҹбһҗбһҸ (folder)бҹ”</li>"
				+ "<li>бһ”бһҫбһҖбһҮбһҳбҹ’бһҡбһҫбһҹ <b>search in archives</b>бҹ”</li>"
				+ "<li>бһ“бҹ…бһҖбҹ’бһ“бһ»бһ„бһўбһҸбҹ’бһҗбһ”бһ‘бһҹбҹ’бһңбҹӮбһ„бһҡбһҖ бһҹбһјбһҳбһңбһ¶бһҷбһ”бһүбҹ’бһ…бһјбһӣ <b>namespace</b> бһ–бҹ„бһӣбһӮбһәбһ•бҹ’бһ“бҹӮбһҖбһҒбһ¶бһ„бһҳбһ»бһҒбһ“бҹғбһҹбһүбҹ’бһүбһ¶бһ–бһёбһҡбһ…бҹҶбһҺбһ»бһ…бҹ– " + "<b>"
				+ namespaceHtml + "</b>бҹ”</li>" + "</ul>"
				+ "<p>бһҮбһ¶бһ’бһҳбҹ’бһҳбһҸбһ¶ бһңбһ¶бһҮбһҪбһҷбһҹбҹ’бһңбҹӮбһ„бһҡбһҖбһҗбһ¶бһҸбһҫбһҜбһҖбһҹбһ¶бһҡ mod бһ¬ datapack бһҺбһ¶бһҠбҹӮбһӣбһҖбҹҶбһ–бһ»бһ„бһ’бҹ’бһңбһҫбһҖбһ¶бһҡбһҷбҹ„бһ„бһҳбһ·бһ“бһҸбҹ’бһҡбһ№бһҳбһҸбҹ’бһҡбһјбһңбҹ”</p>";
	}

